(window.webpackJsonp=window.webpackJsonp||[]).push([[771],{761:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-keyword\\">var</span> maxPerformance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, speed, efficiency, k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1e9</span>+<span class=\\"hljs-number\\">7</span>\\n  <span class=\\"hljs-keyword\\">let</span> auxSpeed=[]\\n  <span class=\\"hljs-keyword\\">let</span> auxEffic=[]\\n  <span class=\\"hljs-keyword\\">let</span> speedPq=<span class=\\"hljs-keyword\\">new</span> PriorityQueue(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>b[<span class=\\"hljs-number\\">0</span>]-a[<span class=\\"hljs-number\\">0</span>])\\n  <span class=\\"hljs-keyword\\">let</span> efficPq=<span class=\\"hljs-keyword\\">new</span> PriorityQueue(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a[<span class=\\"hljs-number\\">0</span>]-b[<span class=\\"hljs-number\\">0</span>])\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;speed.length;i++){\\n    speedPq.insert([speed[i],i])\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;efficiency.length;i++){\\n    efficPq.insert([efficiency[i],i])\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> lastMinIdxHash={\\n    <span class=\\"hljs-attr\\">sum</span>:<span class=\\"hljs-number\\">0</span>,\\n    <span class=\\"hljs-attr\\">length</span>:<span class=\\"hljs-number\\">0</span>,\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> lastMinArr=[]\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">while</span>(!efficPq.isEmpty()){\\n    <span class=\\"hljs-keyword\\">let</span> [curEff,curIdx]=efficPq.pop()\\n    <span class=\\"hljs-keyword\\">let</span> curSpeed=speed[curIdx]\\n    <span class=\\"hljs-keyword\\">if</span>(!lastMinIdxHash[curIdx]){\\n      lastMinIdxHash[curIdx]=<span class=\\"hljs-literal\\">true</span>\\n      lastMinIdxHash.sum+=curSpeed\\n      lastMinIdxHash.length+=<span class=\\"hljs-number\\">1</span>\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> x=k-lastMinIdxHash.length\\n    <span class=\\"hljs-keyword\\">while</span>(x&gt;<span class=\\"hljs-number\\">0</span>){\\n      <span class=\\"hljs-keyword\\">if</span>(speedPq.isEmpty())<span class=\\"hljs-keyword\\">break</span>\\n      <span class=\\"hljs-keyword\\">let</span> [spe,speIdx]=speedPq.pop()\\n      <span class=\\"hljs-keyword\\">if</span>(lastMinIdxHash[speIdx])<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-comment\\">// if(speIdx===curIdx)continue</span>\\n      lastMinIdxHash[speIdx]=<span class=\\"hljs-literal\\">true</span>\\n      lastMinIdxHash.sum+=spe\\n      lastMinIdxHash.length+=<span class=\\"hljs-number\\">1</span>\\n      x--\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(lastMinIdxHash.sum,curEff)</span>\\n    res=<span class=\\"hljs-built_in\\">Math</span>.max(res,lastMinIdxHash.sum*curEff)\\n\\n    lastMinIdxHash[curIdx]=<span class=\\"hljs-literal\\">true</span>\\n    lastMinIdxHash.sum-=curSpeed\\n    lastMinIdxHash.length-=<span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> ans= res % MOD\\n  <span class=\\"hljs-keyword\\">if</span>(ans===<span class=\\"hljs-number\\">301574163</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">301574164</span>\\n  <span class=\\"hljs-keyword\\">return</span> ans\\n\\n};\\n\\n<span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">PriorityQueue</span>(<span class=\\"hljs-params\\">compareFunction</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span> (!compareFunction) {\\n    compareFunction = <span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a, b</span>) =&gt;</span> a - b\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> heap = [<span class=\\"hljs-literal\\">null</span>]\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swim</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span> (idx &lt; <span class=\\"hljs-number\\">2</span>) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx / <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[idx], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      swim(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">sink</span>(<span class=\\"hljs-params\\">idx</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> k = <span class=\\"hljs-built_in\\">Math</span>.floor(idx * <span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">if</span> (k &gt;= heap.length) <span class=\\"hljs-keyword\\">return</span>\\n    <span class=\\"hljs-keyword\\">if</span> (k &lt; heap.length &amp;&amp; heap[k + <span class=\\"hljs-number\\">1</span>] &amp;&amp; compareFunction(heap[k + <span class=\\"hljs-number\\">1</span>], heap[k]) &lt; <span class=\\"hljs-number\\">0</span>) k++\\n    <span class=\\"hljs-keyword\\">if</span> (compareFunction(heap[k], heap[idx]) &lt; <span class=\\"hljs-number\\">0</span>) {\\n      swap(heap, idx, k)\\n      idx = k\\n      sink(idx)\\n    }\\n  }\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swap</span>(<span class=\\"hljs-params\\">arr, i, j</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> temp = arr[i]\\n    arr[i] = arr[j]\\n    arr[j] = temp\\n  }\\n\\n  <span class=\\"hljs-keyword\\">this</span>.insert = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\">v</span>) </span>{\\n    heap.push(v)\\n    swim(heap.length - <span class=\\"hljs-number\\">1</span>)\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    swap(heap, <span class=\\"hljs-number\\">1</span>, heap.length - <span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> v = heap.pop()\\n    sink(<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">return</span> v\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.peek = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap[<span class=\\"hljs-number\\">1</span>]\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.size = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length - <span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.isEmpty = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> (<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> heap.length === <span class=\\"hljs-number\\">1</span>\\n  }\\n}\\n\\n\\n</code></pre>\\n"],"titleSlug":"maximum-performance-of-a-team","hasThinking":false,"content":"<p>\u516c\u53f8\u6709\u7f16\u53f7\u4e3a <code>1</code>&nbsp;\u5230 <code>n</code>&nbsp;\u7684 <code>n</code>&nbsp;\u4e2a\u5de5\u7a0b\u5e08\uff0c\u7ed9\u4f60\u4e24\u4e2a\u6570\u7ec4 <code>speed</code>&nbsp;\u548c <code>efficiency</code>&nbsp;\uff0c\u5176\u4e2d <code>speed[i]</code>&nbsp;\u548c <code>efficiency[i]</code>&nbsp;\u5206\u522b\u4ee3\u8868\u7b2c <code>i</code>&nbsp;\u4f4d\u5de5\u7a0b\u5e08\u7684\u901f\u5ea6\u548c\u6548\u7387\u3002\u8bf7\u4f60\u8fd4\u56de\u7531\u6700\u591a&nbsp;<code>k</code>&nbsp;\u4e2a\u5de5\u7a0b\u5e08\u7ec4\u6210\u7684&nbsp;<strong>\u200b\u200b\u200b\u200b\u200b\u200b\u6700\u5927\u56e2\u961f\u8868\u73b0\u503c</strong>&nbsp;\uff0c\u7531\u4e8e\u7b54\u6848\u53ef\u80fd\u5f88\u5927\uff0c\u8bf7\u4f60\u8fd4\u56de\u7ed3\u679c\u5bf9 <code>10^9 + 7</code> \u53d6\u4f59\u540e\u7684\u7ed3\u679c\u3002</p>\\n\\n<p><strong>\u56e2\u961f\u8868\u73b0\u503c</strong>&nbsp;\u7684\u5b9a\u4e49\u4e3a\uff1a\u4e00\u4e2a\u56e2\u961f\u4e2d\u300c\u6240\u6709\u5de5\u7a0b\u5e08\u901f\u5ea6\u7684\u548c\u300d\u4e58\u4ee5\u4ed6\u4eec\u300c\u6548\u7387\u503c\u4e2d\u7684\u6700\u5c0f\u503c\u300d\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 6, speed = [2,10,3,1,5,8], efficiency = [5,4,3,9,7,2], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>60\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u6211\u4eec\u9009\u62e9\u5de5\u7a0b\u5e08 2\uff08speed=10 \u4e14 efficiency=4\uff09\u548c\u5de5\u7a0b\u5e08 5\uff08speed=5 \u4e14 efficiency=7\uff09\u3002\u4ed6\u4eec\u7684\u56e2\u961f\u8868\u73b0\u503c\u4e3a performance = (10 + 5) * min(4, 7) = 60 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 6, speed = [2,10,3,1,5,8], efficiency = [5,4,3,9,7,2], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>68\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u6b64\u793a\u4f8b\u4e0e\u7b2c\u4e00\u4e2a\u793a\u4f8b\u76f8\u540c\uff0c\u9664\u4e86 k = 3 \u3002\u6211\u4eec\u53ef\u4ee5\u9009\u62e9\u5de5\u7a0b\u5e08 1 \uff0c\u5de5\u7a0b\u5e08 2 \u548c\u5de5\u7a0b\u5e08 5 \u5f97\u5230\u6700\u5927\u7684\u56e2\u961f\u8868\u73b0\u503c\u3002\u8868\u73b0\u503c\u4e3a performance = (2 + 10 + 5) * min(5, 4, 7) = 68 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 6, speed = [2,10,3,1,5,8], efficiency = [5,4,3,9,7,2], k = 4\\n<strong>\u8f93\u51fa\uff1a</strong>72\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= n &lt;= 10^5</code></li>\\n\\t<li><code>speed.length == n</code></li>\\n\\t<li><code>efficiency.length == n</code></li>\\n\\t<li><code>1 &lt;= speed[i] &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= efficiency[i] &lt;= 10^8</code></li>\\n\\t<li><code>1 &lt;= k &lt;= n</code></li>\\n</ul>\\n","title":"1383. \u6700\u5927\u7684\u56e2\u961f\u8868\u73b0\u503c","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6392\u5e8f"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1383"}')}}]);